#include <cuda_runtime.h>
#include <stdlib.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

static float *d_J = NULL;
static float *dN = NULL;
static float *dS = NULL;
static float *dW = NULL;
static float *dE = NULL;
static float *d_c = NULL;
static int g_rows = 0;
static int g_cols = 0;

__global__ void srad_kernel_1(const float *J, float *dN, float *dS, float *dW, float *dE, float *c,
                              int rows, int cols, float q0sqr) {
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;
		float Jc = J[k];

		int iN = (i == 0) ? 0 : (i - 1);
		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jW = (j == 0) ? 0 : (j - 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		dN[k] = J[iN * cols + j] - Jc;
		dS[k] = J[iS * cols + j] - Jc;
		dW[k] = J[i * cols + jW] - Jc;
		dE[k] = J[i * cols + jE] - Jc;

		float G2 = (dN[k] * dN[k] + dS[k] * dS[k] + dW[k] * dW[k] + dE[k] * dE[k]) / (Jc * Jc);
		float L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

		float num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
		float den = 1.0f + (0.25f * L);
		float qsqr = num / (den * den);

		den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
		c[k] = 1.0f / (1.0f + den);

		if (c[k] < 0.0f) c[k] = 0.0f;
		else if (c[k] > 1.0f) c[k] = 1.0f;
	}
}

__global__ void srad_kernel_2(float *J, const float *c, const float *dN, const float *dS, const float *dW, const float *dE,
                              int rows, int cols, float lambda_) {
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;
		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		float cN = c[k];
		float cS = c[iS * cols + j];
		float cW = c[k];
		float cE = c[i * cols + jE];

		float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];
		J[k] = J[k] + 0.25f * lambda_ * D;
	}
}

void srad_cuda_init(int rows, int cols) {
	g_rows = rows;
	g_cols = cols;
	size_t bytes = (size_t)rows * (size_t)cols * sizeof(float);

	cudaMalloc((void**)&d_J, bytes);
	cudaMalloc((void**)&dN, bytes);
	cudaMalloc((void**)&dS, bytes);
	cudaMalloc((void**)&dW, bytes);
	cudaMalloc((void**)&dE, bytes);
	cudaMalloc((void**)&d_c, bytes);
}

void srad_cuda_step(float *h_J, int rows, int cols, float q0sqr, float lambda_) {
	size_t bytes = (size_t)rows * (size_t)cols * sizeof(float);
	cudaMemcpy(d_J, h_J, bytes, cudaMemcpyHostToDevice);

	dim3 block(BLOCK_SIZE, BLOCK_SIZE);
	dim3 grid((cols + block.x - 1) / block.x, (rows + block.y - 1) / block.y);

	srad_kernel_1<<<grid, block>>>(d_J, dN, dS, dW, dE, d_c, rows, cols, q0sqr);
	srad_kernel_2<<<grid, block>>>(d_J, d_c, dN, dS, dW, dE, rows, cols, lambda_);

	cudaMemcpy(h_J, d_J, bytes, cudaMemcpyDeviceToHost);
}

void srad_cuda_cleanup() {
	if (d_J) cudaFree(d_J);
	if (dN) cudaFree(dN);
	if (dS) cudaFree(dS);
	if (dW) cudaFree(dW);
	if (dE) cudaFree(dE);
	if (d_c) cudaFree(d_c);

	d_J = NULL;
	dN = NULL;
	dS = NULL;
	dW = NULL;
	dE = NULL;
	d_c = NULL;
	g_rows = 0;
	g_cols = 0;
}
